```

1. Create a custom hook for data fetching that uses React Query v4 and the singleton supabase client.
2. Implement the getUserContextAction pattern for all user-scoped operations.
3. Add comprehensive error handling and retry mechanisms using React Query's built-in features.
4. Create TypeScript utility types for API responses and error structures.

Example implementation:
```typescript
// hooks/useSupabaseQuery.ts
import { useQuery, QueryKey, UseQueryOptions } from '@tanstack/react-query';
import { createClientComponentClient } from '@supabase/auth-helpers-nextjs';
import { getUserContextAction } from '../lib/auth-helpers';

const supabase = createClientComponentClient();

export function useSupabaseQuery<T>(
  key: QueryKey,
  fetchFn: (supabase: SupabaseClient, userId: string) => Promise<T>,
  options?: UseQueryOptions<T>
) {
  return useQuery<T>(
    key,
    async () => {
      const { user } = await getUserContextAction();
      if (!user) throw new Error('User not authenticated');
      return fetchFn(supabase, user.id);
    },
    {
      retry: 3,
      retryDelay: (attemptIndex) => Math.min(1000 * 2 ** attemptIndex, 30000),
      ...options,
    }
  );
}
```

